import React, { useState } from 'react';

const App = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [filteredImages, setFilteredImages] = useState([]);

  const handleSearch = (e) => {
    setSearchQuery(e.target.value);
    const filtered = images.filter((image) => image.name.toLowerCase().includes(e.target.value.toLowerCase()));
    setFilteredImages(filtered);
  };

  const images = [
    { id: 1, name: 'Image 1', url: 'https://example.com/image1.jpg' },
    { id: 2, name: 'Image 2', url: 'https://example.com/image2.jpg' },
    { id: 3, name: 'Image 3', url: 'https://example.com/image3.jpg' }
  ];

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="max-w-md bg-white p-4 shadow-md">
        <h2 className="text-lg font-bold mb-4">Media Library</h2>
        <input type="search" className="w-full p-2 mb-4" placeholder="Search by name" onChange={handleSearch} value={searchQuery} />
        <ul className="list-none mb-4">
          {filteredImages.map((image) => (
            <li key={image.id} className="py-2 bg-gray-100 rounded-md mb-2">
              <img src={image.url} className="w-20 h-20 object-cover mr-4" alt={image.name} />
              <span className="text-sm font-medium">{image.name}</span>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
